class Solution:
    def findCheapestPrice(self, n, flights, src, dst, k):
        prices = [float('inf')] * n
        prices[src] = 0
        for _ in range(k + 1):
            nxt = prices[:]
            for u, v, w in flights:
                if prices[u] + w < nxt[v]: nxt[v] = prices[u] + w
            prices = nxt
        return -1 if prices[dst] == float('inf') else prices[dst]
```

